const PAGE_HASH = { d: 'Dashboard', q: 'Questions' };
const HASH_PAGE = { Dashboard: 'd', Questions: 'q' };

function showPage(p, pushState=true){
  document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));
  document.querySelectorAll('.nav-btn').forEach(x=>x.classList.remove('active'));
  document.getElementById('page-'+p).classList.add('active');
  const nbEl = document.getElementById('nb-'+p);
  if(nbEl) nbEl.classList.add('active');
  const hash = '#' + (PAGE_HASH[p] || 'Dashboard');
  try { if(pushState && location.hash !== hash) history.pushState({page:p}, '', hash); } catch(e){}
}

window.addEventListener('popstate', e => {
  const p = (e.state && e.state.page) || pageFromHash();
  showPage(p, false);
});

function pageFromHash(){
  try { const h = location.hash.replace('#',''); return HASH_PAGE[h] || 'd'; } catch(e){ return 'd'; }
}

// DASHBOARD
function fmt(s){const d=new Date(s);return d.toLocaleDateString('uk-UA',{day:'2-digit',month:'2-digit',year:'numeric'})+' о '+d.toLocaleTimeString('uk-UA',{hour:'2-digit',minute:'2-digit'})}
function isUp(s){return new Date(s)>new Date()}

function renderDR(){
  const dsEl=document.getElementById('ds');
  const f=(dsEl?dsEl.value:'').toLowerCase();
  const fil=dryRuns.filter(d=>!f||d.name.toLowerCase().includes(f));
  const up=fil.filter(d=>isUp(d.date)),dn=fil.filter(d=>!isUp(d.date));
  const card=(d,t)=>`<div class="dr-card">
    <div class="avatar ${t}"><svg width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" viewBox="0 0 24 24"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg></div>
    <div class="card-info">
      <div class="card-name">${d.name}</div>
      <div class="card-meta">
        <span class="lvl-badge ${t==='dn'?'dn':''}">${d.level}</span>
        <span class="dot">•</span><span>${fmt(d.date)}</span>
        <span class="dot">•</span><span>RM: ${d.rm}</span>
        <span class="dot">•</span><span>Інтерв'юює: ${d.iv}</span>
      </div>
    </div>
    <div style="display:flex;gap:8px;align-items:center">
      <button class="btn-edit">
        <svg width="13" height="13" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
        Редагувати
      </button>
      <button class="btn-p" style="padding:6px 14px;font-size:13px" onclick="startIV(${d.id})">Почати</button>
    </div>
  </div>`;
  const empty=msg=>`<div class="empty"><svg width="32" height="32" fill="none" stroke="#D4D4D8" stroke-width="1.5" viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg><p>${msg}</p></div>`;
  const upEl=document.getElementById('up-list');
  const dnEl=document.getElementById('dn-list');
  if(upEl) upEl.innerHTML=up.length?up.map(d=>card(d,'up')).join(''):empty('Немає запланованих драй-ранів');
  if(dnEl) dnEl.innerHTML=dn.length?dn.map(d=>card(d,'dn')).join(''):empty('Немає завершених драй-ранів');
}

function openDRModal(){
  const now=new Date();now.setHours(now.getHours()+1,0,0,0);
  document.getElementById('fd').value=now.toISOString().slice(0,16);
  document.getElementById('ov-dr').classList.add('open');
}
function saveDR(){
  const name=document.getElementById('fn').value.trim();
  if(!name){document.getElementById('fn').focus();return;}
  dryRuns.push({id:Date.now(),name,level:document.getElementById('fl2').value,date:document.getElementById('fd').value,rm:document.getElementById('frm').value||'—',iv:document.getElementById('fi2').value||'—'});
  document.getElementById('ov-dr').classList.remove('open');
  ['fn','frm','fi2'].forEach(id=>document.getElementById(id).value='');
  renderDR();
}

// QUESTIONS — level filter dropdown
const LVL_LABELS = {A1:'Junior', A2:'Middle', A3:'Senior', A4:'Lead'};
const LVL_CODES = ['A1','A2','A3','A4'];

function buildChips(){ /* no-op */ }

function positionDropdown(btn, dropdown) {
  const r = btn.getBoundingClientRect();
  const dropH = dropdown.offsetHeight;
  const spaceBelow = window.innerHeight - r.bottom;
  if (spaceBelow >= dropH + 8 || spaceBelow >= 120) {
    dropdown.style.top = (r.bottom + 6) + 'px';
    dropdown.style.bottom = 'auto';
  } else {
    dropdown.style.bottom = (window.innerHeight - r.top + 6) + 'px';
    dropdown.style.top = 'auto';
  }
  dropdown.style.left = r.left + 'px';
  // prevent going off right edge
  const dropW = dropdown.offsetWidth;
  if (r.left + dropW > window.innerWidth - 8) {
    dropdown.style.left = (window.innerWidth - dropW - 8) + 'px';
  }
}
function toggleLvlDropdown(){
  const d = document.getElementById('lvl-dropdown');
  const btn = document.getElementById('lvl-filter-btn');
  d.classList.toggle('open');
  if(d.classList.contains('open')) positionDropdown(btn, d);
}
function closeLvlDropdown(){ document.getElementById('lvl-dropdown').classList.remove('open'); }

// null = all selected, [] = none selected, [...] = some selected
// We track: selLvl=null means "All", selLvl=[] means "none", selLvl=[...] means partial

function toggleLvlAll(){
  const allChk = document.getElementById('lvl-chk-all');
  if(selLvl === null){
    // All → uncheck everything
    selLvl = [];
    allChk.checked = false; allChk.indeterminate = false;
    document.querySelectorAll('.lvl-chk').forEach(c => c.checked = false);
  } else {
    // partial or none → select all
    selLvl = null;
    allChk.checked = true; allChk.indeterminate = false;
    document.querySelectorAll('.lvl-chk').forEach(c => c.checked = true);
  }
  updateLvlLabel(); renderQ();
}
function updateLvlFilter(){
  const checked = [...document.querySelectorAll('.lvl-chk:checked')].map(c => c.value);
  const allChk = document.getElementById('lvl-chk-all');
  if(checked.length === LVL_CODES.length){
    selLvl = null;
    allChk.checked = true; allChk.indeterminate = false;
    document.querySelectorAll('.lvl-chk').forEach(c => c.checked = true);
  } else if(checked.length === 0){
    selLvl = [];
    allChk.checked = false; allChk.indeterminate = false;
  } else {
    selLvl = checked;
    allChk.checked = false; allChk.indeterminate = true;
  }
  updateLvlLabel(); renderQ();
}
function updateLvlLabel(){
  const label = document.getElementById('lvl-filter-label');
  if(selLvl === null){ label.textContent = 'Всі рівні'; return; }
  if(selLvl.length === 0){ label.textContent = 'Рівень не обраний'; return; }
  if(selLvl.length === 1){ label.textContent = LVL_LABELS[selLvl[0]]; return; }
  label.textContent = selLvl.map(l => LVL_LABELS[l]).join(', ');
}

document.addEventListener('click', function(e){
  const f = document.getElementById('lvl-filter');
  if(f && !f.contains(e.target)) closeLvlDropdown();
});

