// QUESTION BUILDER
const LEVEL_MAP = {
  'Junior': ['A1','A2'],
  'Middle': ['A2','A3'],
  'Senior': ['A3','A4']
};

const SKILL_ORDER = [
  'General','Requirements gathering','Discovery, Research','Design Process','Design Concept',
  'Validation','UX Documentation',
  'Visual','Visual Design','Visual Research','Visual Research / Branding','UI controls knowledge',
  'Design System','Design System, Consistency','Figma',
  'Dev collaboration','Hand-off to development',
  'Presentation','Client communication, Argumentation','Stakeholder Management',
  'Team Work','Work with feedback','Work with Feedback',
  'Ownership','Proactiveness','Proactiveness, Ownership',
  'Managing Workload, Estimation, Prioritization','Workload Management',
  'Maturity','Trends','Accessibility',
];

function selectLevel(lvl) {
  qbLevel = lvl;
  // Update level buttons
  document.querySelectorAll('.level-btn').forEach(b => b.classList.toggle('on', b.textContent.trim() === lvl));

  // Build skill list for this level
  const lvlCodes = LEVEL_MAP[lvl];
  const filtered = questions.filter(q => q.levels.some(l => lvlCodes.includes(l)));

  // Collect unique skills (split multi-skill entries)
  const skillSet = new Set();
  filtered.forEach(q => {
    q.skill.split(',').forEach(s => { const t = s.trim(); if(t) skillSet.add(t); });
  });
  const skills = [...skillSet].sort((a,b)=>{
    const ai = SKILL_ORDER.indexOf(a);
    const bi = SKILL_ORDER.indexOf(b);
    if(ai===-1 && bi===-1) return a.localeCompare(b);
    if(ai===-1) return 1;
    if(bi===-1) return -1;
    return ai - bi;
  });

  qbSelectedSkills.clear();
  document.getElementById('skills-hint').textContent = `(${filtered.length} питань для рівня ${lvl})`;
  // Reorder for column-first display (col1: 0,3,6... col2: 1,4,7... col3: 2,5,8...)
  const cols = 3;
  const rows = Math.ceil(skills.length / cols);
  const colFirst = [];
  for(let r=0; r<rows; r++){
    for(let c=0; c<cols; c++){
      const idx = c * rows + r;
      if(idx < skills.length) colFirst.push(skills[idx]);
      else colFirst.push(null);
    }
  }

  document.getElementById('skill-chips').innerHTML = colFirst.map(s =>
    s ? `<button class="skill-chip" onclick="toggleSkill(this,'${s.replace(/'/g,"\\'")}')"> ${s}</button>`
      : `<div></div>`
  ).join('');

  document.getElementById('skills-section').style.display = 'block';
  document.getElementById('qb-action').style.display = 'none';
  if (!qbResult.length) document.getElementById('qb-result').style.display = 'none';
  document.getElementById('btn-add-to-list').style.display = 'none';
}

function toggleSkill(el, skill) {
  if (qbSelectedSkills.has(skill)) {
    qbSelectedSkills.delete(skill);
    el.classList.remove('on');
  } else {
    qbSelectedSkills.add(skill);
    el.classList.add('on');
  }
  const hasSkills = qbSelectedSkills.size > 0;
  const actionEl = document.getElementById('qb-action');
  actionEl.style.display = hasSkills ? 'flex' : 'none';
  // show "Додати" button only if there's already a result list
  const addBtn = document.getElementById('btn-add-to-list');
  addBtn.style.display = (hasSkills && qbResult.length > 0) ? 'inline-flex' : 'none';
}

// sorted skill order for questions
const SKILL_NORMALIZE = {
  'work with feedback': 'Work with Feedback',
  'work with feeback':  'Work with Feedback',
  'stakeholder management': 'Stakeholder Management',
  'consistency': 'Consistency',
  'design process': 'Design Process',
};

function normalizeSkill(s) {
  const t = s.trim();
  return SKILL_NORMALIZE[t.toLowerCase()] || t;
}

function getSkills(q) {
  return q.skill.split(',').map(s => normalizeSkill(s));
}

function skillSortIndex(skillStr) {
  const first = skillStr.split(',')[0].trim();
  const i = SKILL_ORDER.indexOf(first);
  return i === -1 ? 999 : i;
}

let qbResult = []; // current displayed questions {q, usedIds per skill}

function buildQuestions() {
  const lvlCodes = LEVEL_MAP[qbLevel];
  const orderedSkills = [...qbSelectedSkills].sort((a,b) => skillSortIndex(a) - skillSortIndex(b));

  const result = [];
  const seen = new Set();
  orderedSkills.forEach(skill => {
    questions
      .filter(q => q.levels.some(l => lvlCodes.includes(l)) && q.skill.split(',').some(t => t.trim() === skill) && !seen.has(q.id))
      .forEach(q => { result.push({q, skill}); seen.add(q.id); });
  });

  qbResult = result;
  renderQBList();
  document.getElementById('qb-result').style.display = 'block';
  document.getElementById('qb-result').scrollIntoView({behavior:'smooth', block:'start'});
  // hide add button after full reset
  document.getElementById('btn-add-to-list').style.display = 'none';
}

function appendQuestions() {
  const lvlCodes = LEVEL_MAP[qbLevel];
  const existingIds = new Set(qbResult.map(r => r.q.id));
  const existingSkills = new Set(qbResult.map(r => r.skill));
  const orderedSkills = [...qbSelectedSkills]
    .filter(s => !existingSkills.has(s))
    .sort((a,b) => skillSortIndex(a) - skillSortIndex(b));

  if (!orderedSkills.length) return;

  const toAdd = [];
  orderedSkills.forEach(skill => {
    questions
      .filter(q => q.levels.some(l => lvlCodes.includes(l)) && q.skill.split(',').some(t => t.trim() === skill) && !existingIds.has(q.id))
      .forEach(q => { toAdd.push({q, skill}); existingIds.add(q.id); });
  });

  if (!toAdd.length) return;
  qbResult = [...qbResult, ...toAdd];
  renderQBList();
  document.getElementById('qb-result').style.display = 'block';
  document.getElementById('qb-result').scrollIntoView({behavior:'smooth', block:'end'});
}

function renderQBList() {
  document.getElementById('qb-count').textContent = `(${qbResult.length} питань)`;
  document.getElementById('qb-questions').innerHTML = qbResult.map((r, i) => `
    <div class="qb-q-item" id="qbitem-${i}" draggable="true" data-idx="${i}">
      <div class="qb-q-drag" title="Перетягнути">
        <svg width="12" height="12" viewBox="0 0 12 12" fill="currentColor"><circle cx="4" cy="2.5" r="1"/><circle cx="8" cy="2.5" r="1"/><circle cx="4" cy="6" r="1"/><circle cx="8" cy="6" r="1"/><circle cx="4" cy="9.5" r="1"/><circle cx="8" cy="9.5" r="1"/></svg>
      </div>
      <div class="qb-q-num">${i+1}.</div>
      <div class="qb-q-body">
        <div class="qb-q-main">
          <div class="qb-q-text">${r.q.question}</div>
          <button class="qb-q-del" onclick="deleteQuestion(${i})" title="Видалити">
            <svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/></svg>
          </button>
        </div>
        <div class="qb-q-badge" style="margin-top:6px">${r.skill}</div>
      </div>
    </div>`).join('');

  // attach drag events
  let dragIdx = null;
  document.querySelectorAll('.qb-q-item').forEach(el => {
    el.addEventListener('dragstart', e => {
      dragIdx = +el.dataset.idx;
      setTimeout(() => el.classList.add('dragging'), 0);
      e.dataTransfer.effectAllowed = 'move';
    });
    el.addEventListener('dragend', () => {
      el.classList.remove('dragging');
      document.querySelectorAll('.qb-q-item').forEach(x => x.classList.remove('drag-over'));
    });
    el.addEventListener('dragover', e => {
      e.preventDefault();
      document.querySelectorAll('.qb-q-item').forEach(x => x.classList.remove('drag-over'));
      el.classList.add('drag-over');
    });
    el.addEventListener('drop', e => {
      e.preventDefault();
      const dropIdx = +el.dataset.idx;
      if (dragIdx === null || dragIdx === dropIdx) return;
      const moved = qbResult.splice(dragIdx, 1)[0];
      qbResult.splice(dropIdx, 0, moved);
      dragIdx = null;
      renderQBList();
    });
  });
}

function deleteQuestion(idx) {
  qbResult.splice(idx, 1);
  renderQBList();
}

(async () => {
  // Load persisted questions if any
  try {
    const stored = await window.storage.get('questions');
    if (stored) questions = JSON.parse(stored.value);
  } catch(e) {}

  renderDR();
  buildChips();
  buildCatOptions();
  selLvl = null;
  selCat = null;
  document.getElementById('lvl-chk-all').checked = true;
  document.querySelectorAll('.lvl-chk').forEach(c => c.checked = true);
  updateLvlLabel();
  document.getElementById('cat-chk-all').checked = true;
  updateCatLabel();
  renderQ();
  showPage(pageFromHash(), false);
  try { history.replaceState({page: pageFromHash()}, '', location.hash || '#Dashboard'); } catch(e){}
})();

function copyToLoop() {
  const text = qbResult.map(r => r.q.question).join('\n');
  copyText(text, 'copy-loop-btn');
}

function copyToExcel() {
  const text = qbResult.map(r => `${r.q.question}\t${r.skill}`).join('\n');
  copyText(text, 'copy-excel-btn');
}

function copyText(text, btnId) {
  const btn = document.getElementById(btnId);
  const orig = btn.innerHTML;
  navigator.clipboard.writeText(text).then(() => {
    btn.innerHTML = '✓ Скопійовано'; btn.disabled = true;
    setTimeout(() => { btn.innerHTML = orig; btn.disabled = false; }, 1500);
  }).catch(() => {
    const ta = document.createElement('textarea');
    ta.value = text; ta.style.cssText = 'position:fixed;opacity:0';
    document.body.appendChild(ta); ta.select();
    document.execCommand('copy'); document.body.removeChild(ta);
    btn.innerHTML = '✓ Скопійовано'; btn.disabled = true;
    setTimeout(() => { btn.innerHTML = orig; btn.disabled = false; }, 1500);
  });
}


